import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"ハーネスエンジニアリング、全員が違うことを言っている — 5社の解釈を並べてみた","description":"","frontmatter":{"title":"ハーネスエンジニアリング、全員が違うことを言っている — 5社の解釈を並べてみた","date":"2026-02-20T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-02-20-harness-engineering-interpretations-zenn-kenimo.md","filePath":"research/ai-articles/scored/2026-02-20-harness-engineering-interpretations-zenn-kenimo.md","lastUpdated":1779894392000}'),i={name:"research/ai-articles/scored/2026-02-20-harness-engineering-interpretations-zenn-kenimo.md"};function l(o,e,s,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<blockquote><p>Source: <a href="https://zenn.dev/kenimo49/articles/harness-engineering-interpretations-2026" target="_blank" rel="noreferrer">https://zenn.dev/kenimo49/articles/harness-engineering-interpretations-2026</a> Fetched: 2026-05-08</p></blockquote><h1 id="ハーネスエンジニアリング、全員が違うことを言っている-—-5社の解釈を並べてみた" tabindex="-1">ハーネスエンジニアリング、全員が違うことを言っている — 5社の解釈を並べてみた <a class="header-anchor" href="#ハーネスエンジニアリング、全員が違うことを言っている-—-5社の解釈を並べてみた" aria-label="Permalink to &quot;ハーネスエンジニアリング、全員が違うことを言っている — 5社の解釈を並べてみた&quot;">​</a></h1><h2 id="「ハーネスエンジニアリング」、定義がバラバラ問題" tabindex="-1">「ハーネスエンジニアリング」、定義がバラバラ問題 <a class="header-anchor" href="#「ハーネスエンジニアリング」、定義がバラバラ問題" aria-label="Permalink to &quot;「ハーネスエンジニアリング」、定義がバラバラ問題&quot;">​</a></h2><p>OpenAIが2026年2月に「Harness engineering」を公開してから、この用語が急速に普及しました。Anthropicは2つのガイドを発表し、LangChainは公式ブログで定義し、martinfowler.comではBirgitta Böckeler氏が解説を執筆し、arXivには関連論文も投稿されています。</p><p>しかし、すべての関係者が微妙に異なることを述べています。同じ「ハーネス」という言葉を使いながら、比喩表現はステアリングから馬具、車体へと多岐にわたり、乗り物図鑑のような様相を呈しています。</p><h2 id="まず共通認識-ハーネス-⊇-コンテキスト-⊇-プロンプト" tabindex="-1">まず共通認識：ハーネス ⊇ コンテキスト ⊇ プロンプト <a class="header-anchor" href="#まず共通認識-ハーネス-⊇-コンテキスト-⊇-プロンプト" aria-label="Permalink to &quot;まず共通認識：ハーネス ⊇ コンテキスト ⊇ プロンプト&quot;">​</a></h2><p>すべての論者が同意する入れ子構造が存在します。SmartScopeの記事によると、「ドキュメントにリンター実行を記載すること」と「Hookで実行を強制すること」の間には、「ほぼ毎回」と「例外なく毎回」という違いがあります。</p><p>この点まではコンセンサスがありますが、ここからが議論の分かれ目です。</p><h2 id="openai-「宣言を書け。コードは書くな」" tabindex="-1">OpenAI：「宣言を書け。コードは書くな」 <a class="header-anchor" href="#openai-「宣言を書け。コードは書くな」" aria-label="Permalink to &quot;OpenAI：「宣言を書け。コードは書くな」&quot;">​</a></h2><p>OpenAIの記事は衝撃的でした。5ヶ月間、エンジニアは「1行もコードを書かず」、100万行を超える本番アプリケーションをCodexエージェントのみで構築しました。ビルド時間は手作業の10分の1に短縮されました。</p><p>OpenAIの見解では、「人間がステアリングを行い、エージェントが実行する」ため、ハーネスとは「宣言的制約」です。つまり、「あるべき状態」を記述し、実装をエージェントに委ねるというアプローチです。</p><p>重点は以下にあります：</p><ul><li>大規模プロジェクトのスケーリング</li><li>エージェントの並列実行</li><li>サンドボックス環境での安全な実行</li></ul><h2 id="anthropic-「コンテキストを管理しろ。モデルは不安になる」" tabindex="-1">Anthropic：「コンテキストを管理しろ。モデルは不安になる」 <a class="header-anchor" href="#anthropic-「コンテキストを管理しろ。モデルは不安になる」" aria-label="Permalink to &quot;Anthropic：「コンテキストを管理しろ。モデルは不安になる」&quot;">​</a></h2><p>Anthropicは2つの公式ガイドを発表していますが、出発点がOpenAIと異なります。OpenAIが「大規模プロジェクト全体の自動化」から始めたのに対し、Anthropicは「長時間動作するエージェントの安定性」から出発しています。</p><p>Anthropicは「context anxiety（コンテキスト不安）」という独自概念を導入しています。AIも過度な情報量で不安定になるということです。</p><p>重点は以下にあります：</p><ul><li>コンテキスト管理による不安回避</li><li>セッション引き継ぎを含むライフサイクル管理</li><li>シングルエージェント設計への簡素化</li></ul><h2 id="langchain-「agent-model-harness。数字で証明する」" tabindex="-1">LangChain：「Agent = Model + Harness。数字で証明する」 <a class="header-anchor" href="#langchain-「agent-model-harness。数字で証明する」" aria-label="Permalink to &quot;LangChain：「Agent = Model + Harness。数字で証明する」&quot;">​</a></h2><p>LangChainの公式ブログは最もシンプルな定義を提供しています。「エージェント」とは「モデル＋ハーネス」であり、モデルは知能をもたらし、ハーネスがその知能を実用的にするとしています。</p><p>重要な点として、ハーネス設計改善のみで、ベンチマーク精度が「52.8%から66.5%」に向上したと定量的に示されました。</p><p>重点は以下にあります：</p><ul><li>モデル非依存の設計原則</li><li>定量的実証</li><li>オーケストレーションとオブザーバビリティツール</li></ul><h2 id="birgitta-bockeler-martinfowler-com-「コードベース自体がハーネスだ」" tabindex="-1">Birgitta Böckeler（martinfowler.com）：「コードベース自体がハーネスだ」 <a class="header-anchor" href="#birgitta-bockeler-martinfowler-com-「コードベース自体がハーネスだ」" aria-label="Permalink to &quot;Birgitta Böckeler（martinfowler.com）：「コードベース自体がハーネスだ」&quot;">​</a></h2><p>Böckeler氏は全く異なる角度を提示しています。強い型付き言語で書かれたコードベースは「自然に型チェックがセンサーになる」と指摘しています。</p><p>つまり、AGENTS.mdを記述する前に、コードベース自体がハーネスの一部として機能しているということです。TypeScriptのstrict modeやRustのBorrow Checkerは、意図せずしてエージェントの品質管理として機能します。</p><p>重点は以下にあります：</p><ul><li>コードベース自体が本質的に持つ制約</li><li>型安全性とテストの価値の再認識</li><li>ハーネスは後付けではなく内在するもの</li></ul><h2 id="arxiv論文-「ハーネスを形式仕様化せよ」" tabindex="-1">arXiv論文：「ハーネスを形式仕様化せよ」 <a class="header-anchor" href="#arxiv論文-「ハーネスを形式仕様化せよ」" aria-label="Permalink to &quot;arXiv論文：「ハーネスを形式仕様化せよ」&quot;">​</a></h2><p>学術的アプローチではさらに異なる視点が提示されています。ハーネスパターンロジックを「読み取り可能かつ実行可能なオブジェクト」として外部化すべきと主張しています。</p><p>重要な知見として、モデルの性能向上にかかわらず、「役割、契約、検証ゲート」といったハーネスレベルの制御が自然言語で指定されることは継続的に価値を持つと述べられています。</p><h2 id="横断比較-何が同じで、何が違うか" tabindex="-1">横断比較：何が同じで、何が違うか <a class="header-anchor" href="#横断比較-何が同じで、何が違うか" aria-label="Permalink to &quot;横断比較：何が同じで、何が違うか&quot;">​</a></h2><h3 id="全員が同意していること" tabindex="-1">全員が同意していること <a class="header-anchor" href="#全員が同意していること" aria-label="Permalink to &quot;全員が同意していること&quot;">​</a></h3><ol><li>モデルの外側が重要</li><li>制約は「お願い」ではなく「強制」すべき</li><li>フィードバックループが必須</li><li>プロンプトエンジニアリングは廃止にはならない</li></ol><h3 id="意見が分かれていること" tabindex="-1">意見が分かれていること <a class="header-anchor" href="#意見が分かれていること" aria-label="Permalink to &quot;意見が分かれていること&quot;">​</a></h3><p><strong>マルチエージェント vs シングルエージェント：</strong></p><ul><li>OpenAI：並列スケーリング</li><li>Anthropic：モデルの進化によりシングルで十分</li></ul><p><strong>ハーネスの粒度：</strong></p><ul><li>OpenAI：プロジェクト全体で1つのハーネス</li><li>Böckeler：型チェック1つもハーネス</li></ul><p><strong>「置き換え」か「積み重ね」か：</strong></p><ul><li>置き換え派：エージェント能力がプロンプト設計の想定を超えた</li><li>積み重ね派：本質的な違いはなく、LLM能力向上の反映</li></ul><h2 id="結局、実務者はどうすればいいのか" tabindex="-1">結局、実務者はどうすればいいのか <a class="header-anchor" href="#結局、実務者はどうすればいいのか" aria-label="Permalink to &quot;結局、実務者はどうすればいいのか&quot;">​</a></h2><p>解釈の相違は興味深いですが、実行段階は単純です。</p><p><strong>ステップ1：</strong> AGENTS.mdまたはCLAUDE.mdを作成（500文字程度で十分）</p><p><strong>ステップ2：</strong> 品質ゲートを自動化（リンター、型チェック、テストをhooksで強制）</p><p><strong>ステップ3：</strong> フィードバックループを実行（エージェントの誤り → AGENTS.mdに制約追加 → 次回以降の改善）</p><p>これら3ステップで、あなたはハーネスエンジニアリングを既に実践しています。各社の解釈の違いは、ステップ3を3ヶ月実行した後に検討すれば十分です。</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li>OpenAI：Harness engineering</li><li>Anthropic：Claude Code Best practices、Building effective agents</li><li>LangChain：The Anatomy of an Agent Harness</li><li>Birgitta Böckeler（martinfowler.com）：Harness Engineering、Exploring Gen AI</li><li>arXiv：Agent Harness Pattern Logic（2603.25723）</li></ul><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><p><strong>原文語言</strong>：日文（分析五個主要組織對「Harness Engineering」的不同詮釋）</p><h3 id="核心命題-同一個詞-五個組織說的是不同的東西" tabindex="-1">核心命題：同一個詞，五個組織說的是不同的東西 <a class="header-anchor" href="#核心命題-同一個詞-五個組織說的是不同的東西" aria-label="Permalink to &quot;核心命題：同一個詞，五個組織說的是不同的東西&quot;">​</a></h3><p>OpenAI 在 2026 年 2 月發布「Harness engineering」後，這個術語迅速普及。但 OpenAI、Anthropic、LangChain、Birgitta Böckeler（martinfowler.com）、arXiv 論文——每個人說的都略有不同。</p><h3 id="共識基礎-harness-⊇-context-⊇-prompt" tabindex="-1">共識基礎：Harness ⊇ Context ⊇ Prompt <a class="header-anchor" href="#共識基礎-harness-⊇-context-⊇-prompt" aria-label="Permalink to &quot;共識基礎：Harness ⊇ Context ⊇ Prompt&quot;">​</a></h3><p>所有論者都同意這個嵌套結構。「文件中記載執行 linter」vs「透過 Hook 強制執行」的差異——「幾乎每次」vs「每次無例外」——這個點有完整共識。分歧從這裡之後才開始。</p><h3 id="五大詮釋對比" tabindex="-1">五大詮釋對比 <a class="header-anchor" href="#五大詮釋對比" aria-label="Permalink to &quot;五大詮釋對比&quot;">​</a></h3><h4 id="openai-「寫宣告-不要寫程式碼」" tabindex="-1">OpenAI：「寫宣告，不要寫程式碼」 <a class="header-anchor" href="#openai-「寫宣告-不要寫程式碼」" aria-label="Permalink to &quot;OpenAI：「寫宣告，不要寫程式碼」&quot;">​</a></h4><ul><li>5 個月、0 行手寫程式碼、100 萬行以上的生產應用，由 Codex agents 獨立構建</li><li>Harness = <strong>宣告式約束</strong>（描述「應有狀態」，把實作委託給 Agent）</li><li>重點：大規模專案擴展、Agent 並列執行、沙箱環境安全執行</li><li>人類負責 steering，Agent 負責執行</li></ul><h4 id="anthropic-「管理-context-模型會不安」" tabindex="-1">Anthropic：「管理 Context，模型會不安」 <a class="header-anchor" href="#anthropic-「管理-context-模型會不安」" aria-label="Permalink to &quot;Anthropic：「管理 Context，模型會不安」&quot;">​</a></h4><ul><li>出發點：「長時間運作 Agent 的穩定性」（vs OpenAI 的「大規模自動化」）</li><li>獨特概念：<strong>Context Anxiety（Context 不安）</strong>——資訊量過大時 AI 也會不穩定</li><li>重點：透過 context 管理避免不安、含 session 交接的生命週期管理、簡化為單一 Agent 設計</li></ul><h4 id="langchain-「agent-model-harness-用數字證明」" tabindex="-1">LangChain：「Agent = Model + Harness，用數字證明」 <a class="header-anchor" href="#langchain-「agent-model-harness-用數字證明」" aria-label="Permalink to &quot;LangChain：「Agent = Model + Harness，用數字證明」&quot;">​</a></h4><ul><li>最簡定義：Agent = 模型（提供智能）+ Harness（讓智能實用化）</li><li>量化驗證：<strong>純靠 harness 設計改善，benchmark 精準度從 52.8% 提升至 66.5%</strong></li><li>重點：模型無關設計原則、量化實證、Orchestration 和 Observability 工具</li></ul><h4 id="birgitta-bockeler-martinfowler-com-「codebase-本身就是-harness」" tabindex="-1">Birgitta Böckeler（martinfowler.com）：「Codebase 本身就是 Harness」 <a class="header-anchor" href="#birgitta-bockeler-martinfowler-com-「codebase-本身就是-harness」" aria-label="Permalink to &quot;Birgitta Böckeler（martinfowler.com）：「Codebase 本身就是 Harness」&quot;">​</a></h4><ul><li>完全不同的角度：以強型別語言撰寫的 codebase 天然讓型別檢查成為感測器</li><li>TypeScript strict mode、Rust Borrow Checker——這些不是後加的 harness，而是<strong>內在的品質管理</strong></li><li>重點：Codebase 本身固有的約束、型別安全和測試的重新認識、Harness 是內在的不是後加的</li></ul><h4 id="arxiv-論文-「形式化-harness-規格」" tabindex="-1">arXiv 論文：「形式化 Harness 規格」 <a class="header-anchor" href="#arxiv-論文-「形式化-harness-規格」" aria-label="Permalink to &quot;arXiv 論文：「形式化 Harness 規格」&quot;">​</a></h4><ul><li>應把 harness 模式邏輯外部化為「可讀且可執行的物件」</li><li>關鍵洞見：無論模型效能如何提升，「角色、合約、驗證閘門」等 harness 層級控制用自然語言指定仍持續有價值</li></ul><h3 id="橫向比較" tabindex="-1">橫向比較 <a class="header-anchor" href="#橫向比較" aria-label="Permalink to &quot;橫向比較&quot;">​</a></h3><p><strong>全員同意的點</strong>：</p><ol><li>模型外側很重要</li><li>約束應「強制」而非「請求」</li><li>反饋循環是必要的</li><li>Prompt Engineering 不會廢止</li></ol><p><strong>意見分歧的點</strong>：</p><table tabindex="0"><thead><tr><th>面向</th><th>OpenAI</th><th>Anthropic</th></tr></thead><tbody><tr><td>代理架構</td><td>多 Agent 並列擴展</td><td>單一 Agent（模型進化使其足夠）</td></tr><tr><td>Harness 粒度</td><td>整個專案一個 harness</td><td>一個型別檢查也算 harness</td></tr><tr><td>演化方向</td><td>置換（新能力超越舊設計假設）</td><td>積層（LLM 能力提升的反映）</td></tr></tbody></table><h3 id="實務三步驟" tabindex="-1">實務三步驟 <a class="header-anchor" href="#實務三步驟" aria-label="Permalink to &quot;實務三步驟&quot;">​</a></h3><p>詮釋的分歧雖有趣，但執行階段其實很簡單：</p><ol><li><strong>建立</strong> AGENTS.md 或 CLAUDE.md（約 500 字元就足夠）</li><li><strong>自動化</strong>品質閘門（linter、型別檢查、測試透過 Hooks 強制）</li><li><strong>執行</strong>反饋循環（Agent 犯錯 → AGENTS.md 加約束 → 下次以後改善）</li></ol><p>這三步就是在實踐 Harness Engineering。各組織詮釋的差異，執行第三步三個月後再研究就夠了。</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>6/10</td><td>3 步驟框架實用但較基本；比較分析對設計決策有參考價值</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>5 家詮釋並排比較有用；無全新概念</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>LangChain 52.8%→66.5% 一個具體數字；其餘為定性分析</td></tr><tr><td>D. 技術深度</td><td>6/10</td><td>Survey 層級；每家觀點概述但不深入</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>比較框架適用理解任何 harness 詮釋差異</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.15/10</strong></td><td>6×0.3+6×0.2+6×0.2+6×0.15+7×0.15 = 1.8+1.2+1.2+0.9+1.05</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（各組織詮釋補充背景）<br><strong>整合狀態</strong>：待實作</p>',80)])])}const u=a(i,[["render",l]]);export{g as __pageData,u as default};
